225	function splitBuy(amm1: AMM, amm2: AMM, totalY: number): [number, number] {
226	  const gamma1 = 1 - amm1.askFee;
227	  const gamma2 = 1 - amm2.askFee;
228	  const a1 = Math.sqrt(amm1.x * gamma1 * amm1.y);
229	  const a2 = Math.sqrt(amm2.x * gamma2 * amm2.y);
230	  if (a2 === 0) return [totalY, 0];
231	  const r = a1 / a2;
232	  const num = r * (amm2.y + gamma2 * totalY) - amm1.y;
233	  const den = gamma1 + r * gamma2;
234	  const y1 = den === 0 ? totalY / 2 : Math.max(0, Math.min(totalY, num / den));
235	  return [y1, totalY - y1];
236	}
