306	    y: INITIAL_Y,
307	    bidFee: clampFee(initFees.bidFee),
308	    askFee: clampFee(initFees.askFee),
309	    strategy,
310	    edge: 0,
311	  };
312	
313	  const competitorAmm: AMM = {
314	    x: INITIAL_X,
315	    y: INITIAL_Y,
316	    bidFee: bpsToFee(30),
317	    askFee: bpsToFee(30),
318	    strategy: null,
