326	    arbitrage(ourAmm, fairPrice, t);
327	    arbitrage(competitorAmm, fairPrice, t);
328	
329	    const numArrivals = poisson(lambda);
330	    for (let i = 0; i < numArrivals; i++) {
331	      const sizeY = lognormal(retailMean, RETAIL_SIZE_SIGMA);
332	      const side: "buy" | "sell" = Math.random() < 0.5 ? "buy" : "sell";
333	      routeRetailOrder(ourAmm, competitorAmm, side, sizeY, fairPrice, t);
334	    }
335	  }
336	
337	  return { edge: ourAmm.edge, competitorEdge: competitorAmm.edge };
338	}
