361	export function createDynamicStrategy(p: DynamicParams): Strategy {
362	  let ewmaVol = 0;
363	  let lastPrice = 0;
364	
365	  const base = bpsToFee(p.baseBps);
366	  const minFee = bpsToFee(p.minBps);
367	  const maxFee = bpsToFee(p.maxBps);
368	  const cl = (f: number) => Math.max(minFee, Math.min(maxFee, f));
369	
370	  return {
371	    name: `Dyn(b=${p.baseBps},a=${p.alpha},vs=${p.volScale},${p.minBps}-${p.maxBps})`,
372	
373	    afterInitialize(initialX: number, initialY: number) {
374	      ewmaVol = 0;
375	      lastPrice = initialY / initialX;
376	      return { bidFee: base, askFee: base };
377	    },
378	
379	    afterSwap(trade: TradeInfo) {
380	      const price = trade.reserveY / trade.reserveX;
381	      lastPrice = price;
382	
383	      if (lastPrice > 0) {
384	        const absRet = Math.abs(price - lastPrice) / lastPrice;
385	        ewmaVol = p.alpha * (absRet * absRet) + (1 - p.alpha) * ewmaVol;
386	      }
387	
388	      const fee = cl(base + Math.sqrt(ewmaVol) * p.volScale);
389	      return { bidFee: fee, askFee: fee };
390	    },
391	  };
392	}
