400	    const { edge, competitorEdge } = runSimulation(strategy);
401	    totalEdge += edge;
402	    totalCompEdge += competitorEdge;
403	    edges.push(edge);
404	  }
405	
406	  edges.sort((a, b) => a - b);
407	  const avg = totalEdge / numSims;
408	  const compAvg = totalCompEdge / numSims;
409	
410	  if (!quiet) {
411	    const median = edges[Math.floor(edges.length / 2)];
412	    const p10 = edges[Math.floor(edges.length * 0.1)];
413	    const p90 = edges[Math.floor(edges.length * 0.9)];
414	
415	    console.log(`\n=== ${strategy.name} ===`);
416	    console.log(`avg edge/sim:    ${avg.toFixed(2)}`);
417	    console.log(`median edge:     ${median!.toFixed(2)}`);
418	    console.log(`p10/p90:         ${p10!.toFixed(2)} / ${p90!.toFixed(2)}`);
419	    console.log(`competitor avg:  ${compAvg.toFixed(2)}`);
420	  }
421	
422	  return { avg, compAvg };
